reg s;
logic condition;
always_comb begin
    s = 1'bz;
    if (condition)
        s = 1'b1;
end

reg s;
logic condition;
always_comb begin
    if (condition)
        s = 1'b1;
    else
        s = 1'bz;
end

reg s;
logic [31:0] cyc;
always_comb begin
    s = 1'bz;
    if (cyc == 0)
        s = 1'b1;
end
always_comb
    s = (cyc == 1) ? 1'b0 : 1'bz;

reg s;
logic condition;
always_comb
    s = condition ? 1'b0 : 1'bz;
